from agents.basic_agent import BasicAgent
import base64
class Base64Agent(BasicAgent):
    def __init__(self):
        self.name = "Base64"
        self.metadata = {"name": "Base64", "description": "Base64 encode or decode UTF-8 text.", "parameters": {"type": "object", "properties": {"action": {"type": "string", "enum": ["encode", "decode"]}, "text": {"type": "string"}}, "required": ["action", "text"]}}
        super().__init__(name=self.name, metadata=self.metadata)
    def perform(self, **kwargs):
        action = (kwargs.get("action") or "encode").strip().lower(); text = kwargs.get("text") or ""
        try:
            if action == "decode": return base64.b64decode(text).decode("utf-8", "replace")
            return base64.b64encode(text.encode("utf-8")).decode("ascii")
        except Exception as e: return f"error: {e}"

from agents.basic_agent import BasicAgent
import codecs
class Rot13Agent(BasicAgent):
    def __init__(self):
        self.name = "Rot13"
        self.metadata = {"name": "Rot13", "description": "Apply the ROT13 substitution cipher to text.", "parameters": {"type": "object", "properties": {"text": {"type": "string"}}, "required": ["text"]}}
        super().__init__(name=self.name, metadata=self.metadata)
    def perform(self, **kwargs):
        try: return codecs.encode(kwargs.get("text") or "", "rot_13")
        except Exception as e: return f"error: {e}"
